}

async function fetchScanProgress(): Promise<ScanProgress> {
  const { data, error } = await supabase
    .from("admin_config")
    .select("key, value")
    .in("key", ["SCAN_PROGRESS", "SCAN_REQUEST"]);

  if (error) throw error;

  const config: Record<string, unknown> = {};
  for (const row of data ?? []) {
